/**
 * TalkingHead – self-contained, loosely-coupled talking avatar.
 *
 * Drop-in for any React app:
 *   1. Serve the character folder (base.webp, sprite_manifest.json, atlases/) from public/.
 *   2. Mount <TalkingHead ref={headRef} avatarDir="/avatars/face1" state={avatarState} />
 *   3. Call headRef.current.speak(text, audioBlob, alignment?) when the AI replies.
 *
 * The component owns its audio element, viseme timeline, and canvas rendering.
 * No application-level context, store, or API calls are made internally.
 */

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from "react";
import { TalkingHeadCanvas } from "./TalkingHeadCanvas";
import {
  buildVisemeTimelineFromAlignment,
  buildVisemeTimelineFromAlignmentAndMap,
  buildVisemeTimelineFromText,
  buildVisemeTimelineFromTextAndMap,
  DEFAULT_FULL_FACE_CONFIG,
  type CharacterAlignment,
  type EyeDestRectPx,
  type EyeSpriteAtlasConfig,
  type EyeSpriteFrame,
  type EyeState,
  type MouthDestRectPx,
  type MouthSpriteAtlasConfig,
  type MouthSpriteFrame,
  type VisemeEvent,
  type VisemeMap,
} from "../lib/visemeTimeline";
import type { AvatarState } from "../lib/avatar";

// ---------------------------------------------------------------------------
// Manifest types (produced by find_common_regions_and_crops.py, formatVersion 1)
// ---------------------------------------------------------------------------

export type SpriteManifest = {
  formatVersion: number;
  group: string;
  base: { file: string; width: number; height: number };
  parts: Array<{
    partIndex: number;
    name: string;
    bboxOnBase: { x: number; y: number; w: number; h: number };
    atlasPages: Array<{
      file: string;
      columns: number;
      rows: number;
      count: number;
      tileW: number;
      tileH: number;
    }>;
  }>;
  frames: Array<{
    imageName: string;
    imageStem: string;
    frameIndex: number;
    parts: Array<{
      partIndex: number;
      pageIndex: number;
      tileIndex: number;
      atlasX: number;
      atlasY: number;
    }>;
  }>;
  /** Optional eye overlay described by the asset pipeline. */
  eyes?: {
    file: string;
    frameWidth: number;
    frameHeight: number;
    destX: number;
    destY: number;
    states: Array<{ state: string; x: number; y: number; width: number; height: number }>;
  };
};

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Imperative handle returned via ref: call speak() / stop() from the parent. */
export type TalkingHeadHandle = {
  /**
   * Start playing audioBlob and animate the mouth in sync.
   * @param text    The spoken text (used as fallback timeline when alignment is absent).
   * @param audioBlob  Pre-fetched audio (mp3, wav, opus …).
   * @param alignment  Optional ElevenLabs character-level timing for accurate lip-sync.
   */
  speak(text: string, audioBlob: Blob, alignment?: CharacterAlignment | null): void;
  /** Stop playback immediately and reset to rest pose. */
  stop(): void;
  /** Character directory currently mounted for this TalkingHead instance. */
  avatarDir: string;
};

export type TalkingHeadProps = {
  /**
   * URL prefix to the avatar folder served from public/ (no trailing slash).
   * Must contain:
   *   base.webp                – static face background
   *   rest.webp                – idle pose (shown when not speaking)
   *   sprite_manifest.json     – crop layout produced by the pipeline
   *   atlases/part0_page0.webp – mouth frames atlas
   *   viseme_map.json          – (optional) viseme→frameIndex map for accurate lip-sync
   * Default: "/avatars/Lucy" (bundled with the SDK via talkyHeadsPlugin).
   */
  avatarDir?: string;
  /**
   * Current avatar state from the application.
   * When "SPEAKING", the canvas animates even without an active audio element.
   * Defaults to "IDLE".
   */
  state?: AvatarState;
  /** CSS class applied to the root element. */
  className?: string;
  /** Show source/dest rect overlays for calibration. Default false. */
  debug?: boolean;
  /** Fine-tune audio/lip-sync alignment in ms. Negative = mouth moves earlier. Default 0. */
  syncOffsetMs?: number;
  /**
   * Display shape of the avatar.
   * "circle" clips to a circle; "square" keeps the default rectangle.
   * Default: "square".
   */
  shape?: "circle" | "square";
  /**
   * Scale factor applied when drawing rest.webp, centred on the canvas.
   * Use a value slightly below 1 (e.g. 0.97) if rest.webp appears marginally
   * larger than the speaking composite — a pipeline asset framing difference.
   * Default: 1 (no adjustment).
   */
  restImageScale?: number;
  /**
   * When true, all cross-frame blending and smoothing is disabled (hard cuts
   * between sprite frames, no interpolation, no imageSmoothingEnabled).
   * Default: false (blending enabled).
   */
  disableBlending?: boolean;
  /**
   * Enable automatic eye-blink animation when an eye spritesheet is present in the
   * character's sprite_manifest.json. Set to false to disable blinking entirely.
   * Default: true.
   */
  blinkEnabled?: boolean;
  /** Notify parent when the internal audio-driven speaking state changes. */
  onSpeakingChange?: (speaking: boolean) => void;
};

// ---------------------------------------------------------------------------
// Manifest → canvas config conversion
// ---------------------------------------------------------------------------

/**
 * Resolve a file path from the manifest relative to avatarDir.
 *
 * Pipeline manifests embed paths prefixed with the group name
 * (e.g. "group_01/atlases/part0_page0.webp"). The actual files are served
 * directly under avatarDir without that prefix, so we strip it here.
 */
function resolveManifestFile(group: string, filePath: string, avatarDir: string): string {
  const prefix = group ? `${group}/` : "";
  const relative = prefix && filePath.startsWith(prefix) ? filePath.slice(prefix.length) : filePath;
  return `${avatarDir}/${relative}`;
}

/**
 * Derive one overlay config per manifest part, plus the resolved baseImageUrl.
 *
 * Each part has its own atlas spritesheet and destination rect on the base face.
 * All parts are animated in sync (same frame index), producing the full composite.
 * Content-only blit (strips tile padding) so the scaled area matches bboxOnBase exactly.
 */
function parseManifest(
  manifest: SpriteManifest,
  avatarDir: string
): {
  overlays: Array<{ atlasConfig: MouthSpriteAtlasConfig; dest: MouthDestRectPx }>;
  baseImageUrl: string;
  eyeAtlasConfig: EyeSpriteAtlasConfig | null;
  eyeDestRect: EyeDestRectPx | null;
} | null {
  const baseImageUrl = resolveManifestFile(manifest.group ?? "", manifest.base.file, avatarDir);

  const overlays = manifest.parts
    .map((part) => {
      const page0 = part.atlasPages[0];
      if (!page0) return null;

      const bbox = part.bboxOnBase;
      const { tileW, tileH } = page0;
      const padX = Math.round((tileW - bbox.w) / 2);
      const padY = Math.round((tileH - bbox.h) / 2);

      const atlasImageUrl = resolveManifestFile(manifest.group ?? "", page0.file, avatarDir);

      // One frame per manifest frame; anchorX/Y = top-center of content area in atlas
      const frames: MouthSpriteFrame[] = manifest.frames.map((frame) => {
        const fp = frame.parts.find((p) => p.partIndex === part.partIndex);
        const ax = fp ? fp.atlasX + padX : 0;
        const ay = fp ? fp.atlasY + padY : 0;
        return {
          anchorX: ax + Math.floor(bbox.w / 2),
          anchorY: ay,
          widthLeft: Math.floor(bbox.w / 2),
          widthRight: Math.ceil(bbox.w / 2),
          heightAbove: 0,
          heightBelow: bbox.h,
          viseme: frame.imageStem,
          phonemes: frame.imageStem,
        };
      });

      if (frames.length === 0) return null;

      const dest: MouthDestRectPx = {
        anchorX: bbox.x + Math.floor(bbox.w / 2),
        anchorY: bbox.y,
        widthLeft: Math.floor(bbox.w / 2),
        widthRight: Math.ceil(bbox.w / 2),
        heightAbove: 0,
        heightBelow: bbox.h,
      };

      return { atlasConfig: { imageUrl: atlasImageUrl, frames }, dest };
    })
    .filter((o): o is { atlasConfig: MouthSpriteAtlasConfig; dest: MouthDestRectPx } => o !== null);

  if (overlays.length === 0) return null;

  // Parse optional eyes section → EyeSpriteAtlasConfig + EyeDestRectPx
  let eyeAtlasConfig: EyeSpriteAtlasConfig | null = null;
  let eyeDestRect: EyeDestRectPx | null = null;
  if (manifest.eyes) {
    const e = manifest.eyes;
    const validStates = new Set<EyeState>(["open", "closed", "half", "smile", "surprised"]);
    const frames: EyeSpriteFrame[] = e.states
      .filter((s) => validStates.has(s.state as EyeState))
      .map((s) => ({ x: s.x, y: s.y, width: s.width, height: s.height, state: s.state as EyeState }));
    if (frames.length > 0) {
      eyeAtlasConfig = {
        imageUrl: resolveManifestFile(manifest.group ?? "", e.file, avatarDir),
        frames,
      };
      eyeDestRect = { x: e.destX, y: e.destY, width: e.frameWidth, height: e.frameHeight };
    }
  }

  return { overlays, baseImageUrl, eyeAtlasConfig, eyeDestRect };
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export const TalkingHead = forwardRef<TalkingHeadHandle, TalkingHeadProps>(
  function TalkingHead(
    {
      avatarDir = "/avatars/Lucy",
      state = "IDLE",
      className = "",
      debug = false,
      syncOffsetMs = 0,
      shape = "square",
      restImageScale = 1,
      disableBlending = false,
      blinkEnabled = true,
      onSpeakingChange,
    },
    ref
  ) {
    const [overlays, setOverlays] = useState<Array<{ atlas: MouthSpriteAtlasConfig; dest: MouthDestRectPx }> | null>(null);
    const [baseImageUrl, setBaseImageUrl] = useState<string | null>(null);
    const [manifestError, setManifestError] = useState<string | null>(null);
    const [visemeMap, setVisemeMap] = useState<VisemeMap | null>(null);
    const [visemeMapLoading, setVisemeMapLoading] = useState(false);
    const [restImageScaleState, setRestImageScaleState] = useState<number>(restImageScale);
    const [eyeAtlasConfig, setEyeAtlasConfig] = useState<EyeSpriteAtlasConfig | null>(null);
    const [eyeDestRect, setEyeDestRect] = useState<EyeDestRectPx | null>(null);
    const [canvasReady, setCanvasReady] = useState(false);

    // Internal audio element – owned by this component, not shared
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);

    const [visemeEvents, setVisemeEvents] = useState<VisemeEvent[]>([]);
    const [internalSpeaking, setInternalSpeaking] = useState(false);
    const currentAudioUrlRef = useRef<string | null>(null);
    const speakingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const pendingPlaybackRef = useRef<(() => void) | null>(null);
    const visemeMapRef = useRef<VisemeMap | null>(null);
    const overlaysRef = useRef<Array<{ atlas: MouthSpriteAtlasConfig; dest: MouthDestRectPx }> | null>(null);
    const canvasReadyRef = useRef(false);
    const visemeMapLoadingRef = useRef(false);

    useEffect(() => {
      visemeMapRef.current = visemeMap;
    }, [visemeMap]);

    useEffect(() => {
      overlaysRef.current = overlays;
    }, [overlays]);

    useEffect(() => {
      canvasReadyRef.current = canvasReady;
    }, [canvasReady]);

    useEffect(() => {
      visemeMapLoadingRef.current = visemeMapLoading;
    }, [visemeMapLoading]);

    const clearSpeakingTimer = useCallback(() => {
      if (speakingTimerRef.current !== null) {
        clearTimeout(speakingTimerRef.current);
        speakingTimerRef.current = null;
      }
    }, []);

    // Create the audio element once
    useEffect(() => {
      const audio = new Audio();
      audioRef.current = audio;
      setAudioEl(audio);
      // Fallback: ensure speaking stops if audio ends before the timer fires
      audio.onended = () => {
        clearSpeakingTimer();
        setInternalSpeaking(false);
        setVisemeEvents([]);
      };
      return () => {
        audio.pause();
        audioRef.current = null;
      };
    }, [clearSpeakingTimer]);

    // Load sprite_manifest.json and optional viseme_map.json whenever avatarDir changes
    useEffect(() => {
      let cancelled = false;
      setManifestError(null);
      setOverlays(null);
      setBaseImageUrl(null);
      setVisemeMap(null);
      setEyeAtlasConfig(null);
      setEyeDestRect(null);
      setVisemeMapLoading(true);
      pendingPlaybackRef.current = null;

      const manifestPromise = fetch(`${avatarDir}/sprite_manifest.json`)
        .then((r) => {
          if (!r.ok) throw new Error(`HTTP ${r.status} loading sprite_manifest.json`);
          return r.json() as Promise<SpriteManifest>;
        });

      const visemeMapPromise = fetch(`${avatarDir}/viseme_map.json`)
        .then((r) => (r.ok ? (r.json() as Promise<VisemeMap>) : null))
        .catch(() => null);

      Promise.all([manifestPromise, visemeMapPromise])
        .then(([manifest, vmap]) => {
          if (cancelled) return;
          const result = parseManifest(manifest, avatarDir);
          if (!result) {
            setManifestError("sprite_manifest.json has no valid parts (empty atlas?)");
            return;
          }
          setOverlays(result.overlays.map((o) => ({ atlas: o.atlasConfig, dest: o.dest })));
          setBaseImageUrl(result.baseImageUrl);
          // If manifest includes a restImageScale, prefer it (pipeline may export this)
          if (typeof (manifest as any).restImageScale === "number") {
            setRestImageScaleState((manifest as any).restImageScale as number);
          } else {
            setRestImageScaleState(restImageScale);
          }
          if (result.eyeAtlasConfig) setEyeAtlasConfig(result.eyeAtlasConfig);
          if (result.eyeDestRect) setEyeDestRect(result.eyeDestRect);
          if (vmap) setVisemeMap(vmap);
        })
        .catch((e) => {
          if (!cancelled)
            setManifestError(e instanceof Error ? e.message : String(e));
        })
        .finally(() => {
          if (!cancelled) {
            setVisemeMapLoading(false);
          }
        });

      return () => {
        cancelled = true;
      };
    }, [avatarDir]);

    const revokeCurrentUrl = useCallback(() => {
      if (currentAudioUrlRef.current) {
        URL.revokeObjectURL(currentAudioUrlRef.current);
        currentAudioUrlRef.current = null;
      }
    }, []);

    const handleCanvasReady = useCallback((ready: boolean) => {
      setCanvasReady(ready);
      if (!ready) {
        console.debug("[TalkyHeads] canvas assets not ready yet; deferring playback if needed");
      }
    }, []);

    useEffect(() => {
      if (canvasReady && !visemeMapLoading && pendingPlaybackRef.current) {
        console.debug("[TalkyHeads] canvas assets ready, resuming deferred playback");
        const resume = pendingPlaybackRef.current;
        pendingPlaybackRef.current = null;
        resume();
      }
    }, [canvasReady, visemeMapLoading]);

    useImperativeHandle(ref, () => ({
      avatarDir,
      speak(text: string, audioBlob: Blob, alignment?: CharacterAlignment | null) {
        const audio = audioRef.current;
        if (!audio) return;
        audio.pause();
        clearSpeakingTimer();
        revokeCurrentUrl();
        pendingPlaybackRef.current = null;

        const url = URL.createObjectURL(audioBlob);
        currentAudioUrlRef.current = url;

        // Start animating only when audio actually begins playing (not during buffering).
        // Stop the speaking state when the viseme timeline ends, not when audio ends,
        // so trailing silence in the audio clip doesn't hold the "speaking" indicator open.
        const startPlayback = (events: VisemeEvent[]) => {
          const lastEventTime = events.length > 0 ? (events[events.length - 1]!.t) : 0;
          const begin = () => {
            // Set both speaking and visemeEvents synchronously so React batches them into
            // one commit. This prevents the race where on cache hits audio starts before
            // visemeEvents are committed, causing the canvas to animate with empty events.
            setVisemeEvents(events);
            setInternalSpeaking(true);
            console.debug(`[TalkyHeads] speak: startPlayback events=${events.length} lastT=${lastEventTime.toFixed(3)}s ready=${canvasReady} t=${performance.now().toFixed(1)}ms`);
            speakingTimerRef.current = setTimeout(() => {
              setInternalSpeaking(false);
              setVisemeEvents([]);
              speakingTimerRef.current = null;
            }, lastEventTime * 1000 + 200);
            audio.play().catch(console.warn);
          };

          if (!canvasReadyRef.current || visemeMapLoadingRef.current) {
            console.debug("[TalkyHeads] speak: deferring playback until canvas + viseme map ready");
            pendingPlaybackRef.current = begin;
            return;
          }

          begin();
        };

        const runWithLatestAssets = () => {
          const currentVisemeMap = visemeMapRef.current;
          const overlaysSnapshot = overlaysRef.current ?? overlays;

          if (alignment && currentVisemeMap) {
            // Best quality: real phoneme timing + per-character frame mapping
            audio.src = url;
            const events = buildVisemeTimelineFromAlignmentAndMap(alignment, currentVisemeMap);
            startPlayback(events);
            return;
          }

          if (alignment) {
            // Real timing but no viseme_map.json — fall back to hardcoded config
            audio.src = url;
            const events = buildVisemeTimelineFromAlignment(alignment, DEFAULT_FULL_FACE_CONFIG);
            startPlayback(events);
            return;
          }

          if (currentVisemeMap) {
            // No timing data but we have the viseme map — use text-based distribution
            audio.src = url;
            const onMeta = () => {
              const dur = isFinite(audio.duration) && audio.duration > 0 ? audio.duration : 2;
              const events = buildVisemeTimelineFromTextAndMap(text, dur, currentVisemeMap);
              startPlayback(events);
              audio.removeEventListener("loadedmetadata", onMeta);
            };
            audio.addEventListener("loadedmetadata", onMeta);
            audio.load();
            return;
          }

          // Oldest fallback: text distribution with frame count only
          const frameCount = overlaysSnapshot?.[0]?.atlas.frames.length;
          audio.src = url;
          const onMeta = () => {
            const dur = isFinite(audio.duration) && audio.duration > 0 ? audio.duration : 2;
            startPlayback(buildVisemeTimelineFromText(text, dur, frameCount));
            audio.removeEventListener("loadedmetadata", onMeta);
          };
          if (audio.readyState >= HTMLMediaElement.HAVE_METADATA) {
            onMeta();
          } else {
            audio.addEventListener("loadedmetadata", onMeta);
          }
        };

        const needsAssets = !canvasReadyRef.current || visemeMapLoadingRef.current;
        if (needsAssets) {
          console.debug("[TalkyHeads] speak: waiting for canvas/viseme-map readiness", { canvasReady: canvasReadyRef.current, visemeMapLoading: visemeMapLoadingRef.current });
          pendingPlaybackRef.current = runWithLatestAssets;
          return;
        }

        runWithLatestAssets();
      },

      stop() {
        clearSpeakingTimer();
        audioRef.current?.pause();
        setInternalSpeaking(false);
        setVisemeEvents([]);
        revokeCurrentUrl();
        pendingPlaybackRef.current = null;
      },
    }), [overlays, visemeMap, revokeCurrentUrl, clearSpeakingTimer, avatarDir]);

    useEffect(() => {
      if (!onSpeakingChange) return;
      onSpeakingChange(internalSpeaking);
    }, [internalSpeaking, onSpeakingChange]);

    const isSpeaking = state === "SPEAKING" || internalSpeaking;

    if (manifestError) {
      return (
        <div
          className={`flex items-center justify-center bg-gray-200 text-red-600 text-sm p-4 rounded ${className}`}
        >
          TalkingHead error: {manifestError}
        </div>
      );
    }

    if (!overlays || !baseImageUrl) {
      return (
        <div
          className={`flex items-center justify-center bg-gray-100 text-gray-400 text-sm p-4 rounded ${className}`}
        >
          Loading avatar…
        </div>
      );
    }

    return (
      <TalkingHeadCanvas
        baseImageUrl={baseImageUrl}
        restImageUrl={`${avatarDir}/rest.webp`}
        restImageScale={restImageScaleState}
        shape={shape}
        audioEl={audioEl}
        visemeEvents={visemeEvents}
        speaking={isSpeaking}
        overlays={overlays}
        visemeMap={visemeMap ?? undefined}
        debug={debug}
        syncOffsetMs={syncOffsetMs}
        className={className}
        disableBlending={disableBlending}
        eyeAtlas={eyeAtlasConfig ?? undefined}
        eyeDest={eyeDestRect ?? undefined}
        blinkEnabled={blinkEnabled}
        onAssetsReady={handleCanvasReady}
      />
    );
  }
);
