import type { TTSFormat, TTSResult } from "../types";

const ELEVENLABS_BASE = "https://api.elevenlabs.io/v1";

type ElevenLabsAlignment = {
  characters: string[];
  character_start_times_seconds: number[];
  character_end_times_seconds: number[];
};

type ElevenLabsTimestampResponse = {
  audio_base64: string;
  alignment?: ElevenLabsAlignment;
  normalized_alignment?: ElevenLabsAlignment;
};

/** Call ElevenLabs /text-to-speech/{voice_id}/with-timestamps directly from the browser. */
export async function elevenLabsSynthesize(
  text: string,
  apiKey: string,
  voiceId: string,
  format: TTSFormat = "mp3",
  speed = 1.0,
  signal?: AbortSignal
): Promise<TTSResult> {
  const outputFormat = format === "mp3" ? "mp3_44100_128" : "pcm_44100";
  const url = `${ELEVENLABS_BASE}/text-to-speech/${voiceId}/with-timestamps?output_format=${outputFormat}`;

  const res = await fetch(url, {
    method: "POST",
    headers: {
      "xi-api-key": apiKey,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      text: text.slice(0, 4096),
      model_id: "eleven_multilingual_v2",
      voice_settings: { speed: Math.max(0.5, Math.min(2.0, speed)) },
    }),
    signal,
  });

  if (!res.ok) {
    const detail = await res.text().catch(() => res.statusText);
    throw new Error(`ElevenLabs TTS failed (${res.status}): ${detail}`);
  }

  const data = (await res.json()) as ElevenLabsTimestampResponse;

  const binary = atob(data.audio_base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  const mimeType = format === "mp3" ? "audio/mpeg" : "audio/wav";
  const audioBlob = new Blob([bytes], { type: mimeType });

  const rawAlignment = data.alignment ?? data.normalized_alignment ?? null;
  const alignment =
    rawAlignment &&
    rawAlignment.characters?.length > 0 &&
    rawAlignment.character_start_times_seconds?.length === rawAlignment.characters.length
      ? rawAlignment
      : null;

  if (alignment) {
    console.group(`[TalkyHeads] ElevenLabs alignment — "${text.slice(0, 60)}${text.length > 60 ? "…" : ""}"`);
    console.table(
      alignment.characters.map((ch, i) => ({
        char: ch,
        start_s: alignment.character_start_times_seconds[i]?.toFixed(3),
        end_s:   alignment.character_end_times_seconds[i]?.toFixed(3),
      }))
    );
    console.groupEnd();
  } else {
    console.warn("[TalkyHeads] ElevenLabs returned no alignment — lip-sync will use text-based fallback.");
  }

  return { audioBlob, alignment };
}
