import { useCallback, useRef, useState } from "react";
import { TalkingHead, type TalkingHeadHandle } from "./TalkingHead";
import { useTTS } from "../tts/useTTS";
import type { TTSConfig } from "../tts/types";
import type { AvatarState } from "../lib/avatar";

export type TalkingHeadWithTTSProps = {
  /** Path under public/ containing avatar assets. Defaults to "/avatars/Lucy". */
  avatarDir?: string;
  /** TTS configuration — proxy URL or direct API key. */
  ttsConfig: TTSConfig;
  /** Placeholder text for the input box. */
  placeholder?: string;
  className?: string;
  /** Inline styles for the root element (e.g. `{ width: 340, height: 420 }`). */
  style?: React.CSSProperties;
  debug?: boolean;
  /**
   * Display shape of the avatar. "circle" clips to a circle; "square" keeps rectangle.
   * Default: "square".
   */
  shape?: "circle" | "square";
  /** Fine-tune audio/lip-sync alignment in ms. Negative = mouth moves earlier. Default 0. */
  syncOffsetMs?: number;
  /**
   * When true, disables all cross-frame blending and smoothing (hard cuts between frames).
   * Default: false.
   */
  disableBlending?: boolean;
  /**
   * Scale factor for rest.webp, centred on the canvas. Use slightly below 1 (e.g. 0.97) if
   * the idle image appears marginally larger than the speaking composite. Default: 1.
   */
  restImageScale?: number;
};

const S = {
  root: {
    display: "flex",
    flexDirection: "column" as const,
    gap: "12px",
  },
  inputRow: {
    display: "flex",
    gap: "8px",
    alignItems: "flex-end",
  },
  textarea: {
    flex: 1,
    resize: "none" as const,
    borderRadius: "8px",
    border: "1px solid #d1d5db",
    padding: "8px 12px",
    fontSize: "14px",
    fontFamily: "inherit",
    lineHeight: 1.5,
    outline: "none",
  },
  speakBtn: {
    flexShrink: 0,
    padding: "9px 20px",
    borderRadius: "8px",
    background: "#6366f1",
    color: "#fff",
    fontSize: "13px",
    fontWeight: 600,
    border: "none",
    cursor: "pointer",
    transition: "background 0.15s",
  },
  speakBtnDisabled: {
    background: "#a5b4fc",
    cursor: "not-allowed",
  },
  error: {
    fontSize: "12px",
    color: "#dc2626",
    marginTop: "2px",
  },
};

/**
 * Complete ready-to-use component: avatar + text input + speak button.
 *
 * Example:
 *   <TalkingHeadWithTTS
 *     ttsConfig={{ mode: "proxy", proxyUrl: "http://localhost:3001", provider: "elevenlabs" }}
 *   />
 */
export function TalkingHeadWithTTS({
  avatarDir = "/avatars/Lucy",
  ttsConfig,
  placeholder = "Type something for the avatar to say…",
  className = "",
  style,
  debug = false,
  shape,
  syncOffsetMs,
  disableBlending,
  restImageScale,
}: TalkingHeadWithTTSProps) {
  const headRef = useRef<TalkingHeadHandle>(null);
  const [text, setText] = useState("");
  const [avatarState, setAvatarState] = useState<AvatarState>("IDLE");
  const { synthesize, loading, error } = useTTS(ttsConfig);

  const handleSpeakingChange = useCallback((speaking: boolean) => {
    setAvatarState((prev) => {
      if (speaking) return "SPEAKING";
      return prev === "SPEAKING" ? "IDLE" : prev;
    });
  }, []);

  const handleSpeak = async () => {
    const trimmed = text.trim();
    if (!trimmed || loading) return;

    try {
      setAvatarState("THINKING");
      const { audioBlob, alignment } = await synthesize(trimmed);
      setAvatarState("SPEAKING");
      headRef.current?.speak(trimmed, audioBlob, alignment);
    } catch {
      setAvatarState("IDLE");
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSpeak();
    }
  };

  const btnStyle = {
    ...S.speakBtn,
    ...(loading || !text.trim() ? S.speakBtnDisabled : {}),
  };

  return (
    <div style={{ ...S.root, ...style }} className={className}>
      <TalkingHead
        ref={headRef}
        avatarDir={avatarDir}
        state={avatarState}
        debug={debug}
        {...(shape !== undefined && { shape })}
        {...(syncOffsetMs !== undefined && { syncOffsetMs })}
        {...(disableBlending !== undefined && { disableBlending })}
        {...(restImageScale !== undefined && { restImageScale })}
        onSpeakingChange={handleSpeakingChange}
      />

      <div style={S.inputRow}>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          rows={2}
          disabled={loading}
          style={{
            ...S.textarea,
            opacity: loading ? 0.6 : 1,
          }}
        />
        <button
          onClick={handleSpeak}
          disabled={loading || !text.trim()}
          style={btnStyle}
        >
          {loading ? "…" : "Speak"}
        </button>
      </div>

      {error && <p style={S.error}>TTS error: {error}</p>}
    </div>
  );
}
