/**
 * TalkingHeadCanvas: composite avatar = parent face image + mouth sprite sheet overlay.
 * Renders a canvas; loads parent.png and mouth sprite image; draws base face and
 * the selected mouth section (sx,sy,sw,sh) from the sprite sheet on top at a fixed
 * destination rectangle (dx,dy,dw,dh) on the face.
 */
import {
  useCallback,
  useEffect,
  useRef,
  useState,
} from "react";
import {
  DEFAULT_MOUTH_SPRITE_ATLAS,
  DEFAULT_MOUTH_DEST_RECT_PX,
  DEFAULT_EYE_SPRITE_ATLAS,
  DEFAULT_EYE_DEST_RECT_PX,
  DEMO_VISEME_INTERVAL,
  getVisemeAtTime,
  getInterpolatedVisemeAtTime,
  smoothstep,
  getFrameRect,
  getDestRect,
  getDestRectForFrame,
  pickVisemeFrame,
  type MouthSpriteAtlasConfig,
  type MouthDestRectPx,
  type EyeSpriteAtlasConfig,
  type EyeDestRectPx,
  type EyeState,
  type VisemeEvent,
  type VisemeMap,
} from "../lib/visemeTimeline";

const BASE = typeof import.meta !== "undefined" && import.meta.env?.BASE_URL ? import.meta.env.BASE_URL.replace(/\/$/, "") : "";
/** Default base face image (public folder) – used when baseImageUrl prop is not supplied. */
const DEFAULT_PARENT_IMAGE_URL = `${BASE}/parent.png`;
/** Fallback mouth atlas if modifiedmouthsprite.png is missing (e.g. before running fix-mouth-tone). */
const MOUTH_ATLAS_FALLBACK_URL = `${BASE}/mouthsprite.png`;
/** Crossfade duration between viseme sprites (~5 frames at 60fps) for demo mode. */
const CROSSFADE_DURATION_S = 5 / 60;
/** Arrival crossfade duration for timeline mode: smooth fade-in when a new frame arrives. */
const ARRIVAL_DURATION_S = 4 / 60; // ~67ms at 60fps

export type TalkingHeadCanvasProps = {
  /**
   * URL of the base face image.  Defaults to /parent.png (served from public/).
   * Pass a character-specific URL such as "/avatars/face1/base.webp" to use
   * an asset produced by the processing pipeline.
   */
  baseImageUrl?: string;
  /**
   * Optional pre-composited idle/rest image (e.g. "rest.webp" next to base.webp).
   * Shown as-is when the avatar is not speaking, replacing base.webp + overlays.
   * Falls back to base.webp silently if this URL is absent or fails to load.
   */
  restImageUrl?: string;
  /**
   * Scale factor applied when drawing rest.webp, centred on the canvas.
   * Use a value slightly below 1 (e.g. 0.97) if rest.webp appears marginally
   * larger than the base + sprite composite — a common pipeline artefact where
   * the two images have the same pixel dimensions but slightly different face
   * framing. Default: 1 (draw at full canvas size, no adjustment).
   */
  restImageScale?: number;
  /** Optional audio element to sync viseme time to playback */
  audioEl?: HTMLAudioElement | null;
  /** Viseme timeline: t (seconds), v (mouth index 0..N-1). If not provided, demo loop when speaking. */
  visemeEvents?: VisemeEvent[];
  /** When true, mouth animates (timeline or demo loop); when false, show frame 0 (closed). */
  speaking?: boolean;
  /** Canvas width (defaults to parent image natural width) */
  width?: number;
  /** Canvas height (defaults to parent image natural height) */
  height?: number;
  /** Debug mode: draw dest rect outline and show sx/sy/sw/sh & dx/dy/dw/dh */
  debug?: boolean;
  /** Override atlas config (e.g. from calibration) */
  atlas?: MouthSpriteAtlasConfig;
  /** Override mouth destination rect in pixels (e.g. from calibration) */
  mouthDest?: MouthDestRectPx;
  /**
   * Multi-part overlays produced by parseManifest (one per character part).
   * When provided, supersedes the single atlas/mouthDest pair.
   * All parts animate in sync at the same frame index.
   */
  overlays?: Array<{ atlas: MouthSpriteAtlasConfig; dest: MouthDestRectPx }>;
  /**
   * Display shape of the avatar container.
   * "circle" clips the canvas to a circle; "square" uses the default rectangle.
   * Default: "square".
   */
  shape?: "circle" | "square";
  /** Mouth speed relative to audio: 1 = in sync, <1 = slower, >1 = faster (default 1) */
  mouthSpeed?: number;
  /** When set, show this frame on the parent (for calibration); overrides animation */
  previewMouthIndex?: number | null;
  /** Called when the current mouth index changes (for calibration UI) */
  onMouthIndexChange?: (index: number) => void;
  /** Eyes overlay: atlas config (default DEFAULT_EYE_SPRITE_ATLAS) */
  eyeAtlas?: EyeSpriteAtlasConfig;
  /** Eyes overlay: destination rect on parent (default DEFAULT_EYE_DEST_RECT_PX) */
  eyeDest?: EyeDestRectPx;
  /** Override current eye state (open/closed/smile/surprised/half); if set, blink is disabled */
  eyeState?: EyeState;
  /** Override current eye frame index (0..N-1); if set, blink is disabled */
  eyeFrameIndex?: number;
  /** Enable natural blinking when eyeState/eyeFrameIndex not set (default true) */
  blinkEnabled?: boolean;
  /** Sync offset in ms: t = audio.currentTime + syncOffsetMs/1000. Negative = mouth earlier. Default 0. */
  syncOffsetMs?: number;
  /** Called periodically with current audio time, offset, and viseme index (for calibration UI). */
  onTick?: (info: { audioTimeSec: number; syncOffsetSec: number; visemeIndex: number }) => void;
  /**
   * viseme_map.json data for this character. When provided, VisemeEvent.v is
   * treated as a direct atlas frameIndex (not a range-array index). Also used
   * to compute the REST frameIndex for pause/idle detection.
   */
  visemeMap?: VisemeMap;
  className?: string;
  /**
   * When true, all cross-frame blending and smoothing is disabled:
   * - ROI crossfade between viseme sprites is skipped (hard cuts between frames)
   * - Interpolated coarticulation blend is skipped (jump straight to the target frame)
   * - Canvas imageSmoothingEnabled is set to false
   * - The brightness/contrast/saturate filter on sprite draws is removed
   * Default: false (blending enabled).
   */
  disableBlending?: boolean;
  /** Notify parent whenever critical assets (base + mouth atlases) finish loading. */
  onAssetsReady?: (ready: boolean) => void;
};

export function TalkingHeadCanvas({
  baseImageUrl: baseImageUrlProp,
  restImageUrl: restImageUrlProp,
  restImageScale = 1,
  shape = "square",
  audioEl = null,
  visemeEvents = [],
  speaking = false,
  width: widthProp,
  height: heightProp,
  debug = false,
  atlas: atlasOverride,
  mouthDest: mouthDestOverride,
  overlays: overlaysProp,
  mouthSpeed: mouthSpeedProp = 1,
  previewMouthIndex,
  onMouthIndexChange,
  eyeAtlas: eyeAtlasOverride,
  eyeDest: eyeDestOverride,
  eyeState: eyeStateOverride,
  eyeFrameIndex: eyeFrameIndexOverride,
  blinkEnabled = true,
  syncOffsetMs = 0,
  onTick,
  visemeMap: visemeMapProp,
  className = "",
  disableBlending = false,
  onAssetsReady,
}: TalkingHeadCanvasProps) {
  const syncOffsetSec = syncOffsetMs / 1000;
  const mouthSpeed = Math.max(0.3, Math.min(2, mouthSpeedProp));
  const fallbackImageUrl = (() => {
    const src = restImageUrlProp ?? baseImageUrlProp ?? DEFAULT_PARENT_IMAGE_URL;
    if (!src) return undefined;
    return src.startsWith("/") ? `${BASE}${src}` : src;
  })();

  // When visemeMap is provided, VisemeEvent.v is a direct atlas frameIndex.
  // Derive the REST frameIndex so pause/idle detection works for any character.
  const restFrameIndex = visemeMapProp
    ? (() => {
      const restFrames = visemeMapProp.visemeFrames["REST"];
      return restFrames && restFrames.length > 0 ? pickVisemeFrame(restFrames) : 0;
    })()
    : 0;

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [loaded, setLoaded] = useState(false);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [mouthLoadError, setMouthLoadError] = useState<string | null>(null);
  const [eyeLoadError, setEyeLoadError] = useState<string | null>(null);
  const [parentNaturalSize, setParentNaturalSize] = useState<{ width: number; height: number } | null>(null);

  const parentImageRef = useRef<HTMLImageElement | null>(null);
  const restImageRef = useRef<HTMLImageElement | null>(null);
  const overlayImagesRef = useRef<HTMLImageElement[]>([]);
  const eyeAtlasRef = useRef<HTMLImageElement | null>(null);

  // ROI crossfade: two persistent OffscreenCanvases for rendering overlay frames,
  // one blend result canvas, and a per-frame-pair feathered mask cache.
  const offscreenARef = useRef<OffscreenCanvas | null>(null);
  const offscreenBRef = useRef<OffscreenCanvas | null>(null);
  const offscreenBlendRef = useRef<OffscreenCanvas | null>(null);
  // key: "fromIdx→toIdx" → Float32Array mask (0..1 per pixel)
  const roiMaskCacheRef = useRef<Map<string, Float32Array>>(new Map());
  // Tracks speaking state without causing callback re-creation
  const isSpeakingRef = useRef(speaking);
  isSpeakingRef.current = speaking;
  // Tracks blending toggle without causing callback re-creation
  const disableBlendingRef = useRef(disableBlending);
  disableBlendingRef.current = disableBlending;
  const rafRef = useRef<number>(0);
  const lastMouthIndexRef = useRef<number>(-1);
  const demoStartTimeRef = useRef<number>(0);
  const previousVisemeRef = useRef<number>(-1);
  const currentVisemeRef = useRef<number>(-1);
  const transitionStartTimeRef = useRef<number>(0);
  // Timeline-mode arrival crossfade: tracks the frame we're fading FROM and when it started
  const arrivalFromRef = useRef<number>(-1);
  const arrivalStartRef = useRef<number>(0);
  const arrivalPrevPrimaryRef = useRef<number>(-1);
  const lastMouthDestRef = useRef<string>("");
  const lastAtlasFrameKeyRef = useRef<string>("");
  const lastEyeCalibrationKeyRef = useRef<string>("");
  const lastResolvedEyeFrameIndexRef = useRef<number>(0);

  const atlas: MouthSpriteAtlasConfig = atlasOverride ?? DEFAULT_MOUTH_SPRITE_ATLAS;
  const eyeAtlas: EyeSpriteAtlasConfig = eyeAtlasOverride ?? DEFAULT_EYE_SPRITE_ATLAS;
  const eyeDest: EyeDestRectPx = eyeDestOverride ?? DEFAULT_EYE_DEST_RECT_PX;
  // Ensure mouthDest has the correct structure (anchorX, anchorY, etc.)
  // If it has old format (baseAnchorX, scaleX, etc.), use defaults
  let mouthDest: MouthDestRectPx = mouthDestOverride ?? DEFAULT_MOUTH_DEST_RECT_PX;
  if (!mouthDest || !("anchorX" in mouthDest) || !("anchorY" in mouthDest) ||
    !("widthLeft" in mouthDest) || !("widthRight" in mouthDest) ||
    !("heightAbove" in mouthDest) || !("heightBelow" in mouthDest)) {
    console.warn("TalkingHeadCanvas - Invalid mouthDest structure, using defaults:", mouthDest);
    mouthDest = DEFAULT_MOUTH_DEST_RECT_PX;
  }

  // When overlays prop is provided (multi-part character) it supersedes the single atlas/mouthDest.
  const effectiveOverlays: Array<{ atlas: MouthSpriteAtlasConfig; dest: MouthDestRectPx }> =
    overlaysProp && overlaysProp.length > 0
      ? overlaysProp
      : [{ atlas, dest: mouthDest }];

  // Keep a ref so animation callbacks always read the latest overlays without re-creation.
  const effectiveOverlaysRef = useRef(effectiveOverlays);
  effectiveOverlaysRef.current = effectiveOverlays;

  // Primary atlas drives frame-count / debug labels (first overlay = most prominent region)
  const primaryAtlas = effectiveOverlays[0].atlas;
  const primaryDest = effectiveOverlays[0].dest;

  useEffect(() => {
  }, [primaryDest, parentNaturalSize, debug, primaryAtlas]);

  const [currentMouthIndex, setCurrentMouthIndex] = useState(0);

  const getCurrentTime = useCallback((): number => {
    if (audioEl && !isNaN(audioEl.currentTime)) return audioEl.currentTime + syncOffsetSec;
    return (performance.now() - demoStartTimeRef.current) / 1000;
  }, [audioEl, syncOffsetSec]);

  const getCurrentVisemeIndex = useCallback((): number => {
    const t = getCurrentTime();
    const runCycle = speaking || debug;
    if (!runCycle) return 0;
    if (visemeEvents.length > 0 && speaking) {
      const idx = getVisemeAtTime(visemeEvents, t);
      return Math.max(0, Math.min(idx, primaryAtlas.frames.length - 1));
    }
    if (audioEl && speaking && Number.isFinite(audioEl.duration) && audioEl.duration > 0) {
      const duration = audioEl.duration;
      const progress = Math.max(0, Math.min(1, t / duration));
      const frameIndex = Math.floor(progress * primaryAtlas.frames.length) % Math.max(1, primaryAtlas.frames.length);
      return frameIndex;
    }
    const frame = Math.floor(t / DEMO_VISEME_INTERVAL) % primaryAtlas.frames.length;
    return frame;
  }, [speaking, debug, visemeEvents, getCurrentTime, primaryAtlas.frames.length, audioEl]);

  /** When using timeline: interpolated state for 60fps coarticulation blend. Uses mouthSpeed to scale time. */
  const getInterpolatedViseme = useCallback(() => {
    const t = getCurrentTime() * mouthSpeed;
    return getInterpolatedVisemeAtTime(visemeEvents, t);
  }, [visemeEvents, getCurrentTime, mouthSpeed]);

  const onTickRef = useRef(onTick);
  onTickRef.current = onTick;
  const lastOnTickTimeRef = useRef(0);

  // --- Eye frame index: from props or blink controller ---
  const [autoEyeFrameIndex, setAutoEyeFrameIndex] = useState(0); // 0 = open, used when blinkEnabled and no override
  const blinkTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const resolvedEyeFrameIndex =
    eyeFrameIndexOverride !== undefined && eyeFrameIndexOverride !== null
      ? Math.max(0, Math.min(eyeFrameIndexOverride, eyeAtlas.frames.length - 1))
      : eyeStateOverride !== undefined
        ? (() => {
          const i = eyeAtlas.frames.findIndex((f) => f.state === eyeStateOverride);
          return i >= 0 ? i : 0;
        })()
        : blinkEnabled
          ? Math.max(0, Math.min(autoEyeFrameIndex, eyeAtlas.frames.length - 1))
          : 0;

  // Keep a ref to the current eye atlas config so blink timeouts always read
  // the latest frame layout without the effect needing to re-run on atlas changes.
  const eyeAtlasConfigRef = useRef(eyeAtlas);
  eyeAtlasConfigRef.current = eyeAtlas;

  // Blink controller: open -> half -> closed -> half -> open over ~160ms, next blink 3–6s
  // (slightly more frequent when speaking). Frame indices are derived from the atlas so the
  // blink works correctly for any eye spritesheet (3-frame or 5-frame, any ordering).
  useEffect(() => {
    if (!blinkEnabled || eyeStateOverride !== undefined || (eyeFrameIndexOverride !== undefined && eyeFrameIndexOverride !== null)) return;

    // Always reset to open eyes when the controller (re)starts so eyes are never
    // stuck on "half" or "closed" from a previously interrupted blink cycle.
    const frames = eyeAtlasConfigRef.current.frames;
    const OPEN = Math.max(0, frames.findIndex((f) => f.state === "open"));
    setAutoEyeFrameIndex(OPEN);

    const scheduleNextBlink = () => {
      const minMs = speaking ? 2500 : 3000;
      const maxMs = speaking ? 5000 : 6000;
      const delay = minMs + Math.random() * (maxMs - minMs);
      blinkTimeoutRef.current = setTimeout(startBlink, delay);
    };

    const startBlink = () => {
      const f = eyeAtlasConfigRef.current.frames;
      const openIdx = Math.max(0, f.findIndex((fr) => fr.state === "open"));
      const closedIdx = f.findIndex((fr) => fr.state === "closed");
      const halfIdx = f.findIndex((fr) => fr.state === "half");
      const half = halfIdx >= 0 ? halfIdx : closedIdx >= 0 ? closedIdx : openIdx;
      const closed = closedIdx >= 0 ? closedIdx : openIdx;

      setAutoEyeFrameIndex(half);
      blinkTimeoutRef.current = setTimeout(() => {
        setAutoEyeFrameIndex(closed);
        blinkTimeoutRef.current = setTimeout(() => {
          setAutoEyeFrameIndex(half);
          blinkTimeoutRef.current = setTimeout(() => {
            setAutoEyeFrameIndex(openIdx);
            scheduleNextBlink();
          }, 40);
        }, 40);
      }, 40);
    };

    scheduleNextBlink();
    return () => {
      if (blinkTimeoutRef.current) clearTimeout(blinkTimeoutRef.current);
      blinkTimeoutRef.current = null;
    };
  }, [blinkEnabled, speaking, eyeStateOverride, eyeFrameIndexOverride]);

  /**
   * Draw rest.webp centred on the canvas at the requested scale.
   * A scale < 1 shrinks the image towards the centre, compensating for pipeline
   * framing differences where rest.webp was generated at a tighter crop than base.webp.
   */
  const drawRest = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number) => {
      const rest = restImageRef.current;
      if (!rest?.complete || !rest.naturalWidth) return;
      if (restImageScale === 1) {
        ctx.drawImage(rest, 0, 0, rest.naturalWidth, rest.naturalHeight, 0, 0, w, h);
      } else {
        const dw = w * restImageScale;
        const dh = h * restImageScale;
        const dx = (w - dw) / 2;
        const dy = (h - dh) / 2;
        ctx.drawImage(rest, 0, 0, rest.naturalWidth, rest.naturalHeight, dx, dy, dw, dh);
      }
    },
    [restImageScale]
  );

  /** Draw base (parent face) only; used before drawing mouth with crossfade. */
  const drawBase = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number) => {
      const parent = parentImageRef.current;
      if (!parent?.complete || !parent.naturalWidth) return;
      // Fill white first. base.webp has transparent holes (pipeline punches out
      // mouth/eye regions for sprite compositing). Without this fill, accumulated
      // canvas state from previous frames can bleed through those holes and create
      // a tinted background. An explicit white fill guarantees neutral pixels under
      // those holes regardless of any CSS background or browser compositing quirk.
      // This does NOT cause flicker: crossfade now draws the outgoing overlay at
      // alpha=1 first (fully covering the holes) before blending the incoming frame.
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, w, h);
      ctx.drawImage(parent, 0, 0, parent.naturalWidth, parent.naturalHeight, 0, 0, w, h);
    },
    []
  );

  /** Draw eyes overlay at eyeDest using selected frame from eyeAtlas. Exact (sx,sy,sw,sh) -> (dx,dy,dw,dh). */
  const drawEyesOnly = useCallback(
    (ctx: CanvasRenderingContext2D, eyeFrameIndex: number) => {
      const eyeImg = eyeAtlasRef.current;
      if (!eyeImg?.complete || !eyeImg.naturalWidth || !eyeImg.naturalHeight) return;

      const clamped = Math.max(0, Math.min(eyeFrameIndex, eyeAtlas.frames.length - 1));
      const frame = eyeAtlas.frames[clamped];
      if (!frame) return;

      const { x: sx, y: sy, width: sw, height: sh } = frame;
      const { x: dx, y: dy, width: dw, height: dh } = eyeDest;

      const ew = eyeImg.naturalWidth;
      const eh = eyeImg.naturalHeight;
      if (sx + sw > ew || sy + sh > eh || sx < 0 || sy < 0) {
        if (clamped === 0) console.warn("TalkingHeadCanvas - Eye frame 0 source rect outside atlas", { sx, sy, sw, sh, atlasSize: [ew, eh] });
        return;
      }

      ctx.drawImage(eyeImg, sx, sy, sw, sh, dx, dy, dw, dh);
    },
    [eyeAtlas, eyeDest]
  );

  /** Draw one overlay's sprite at the given frame index and alpha. All params explicit for stability. */
  const drawOneOverlay = useCallback(
    (
      ctx: CanvasRenderingContext2D,
      ovAtlas: MouthSpriteAtlasConfig,
      ovDest: MouthDestRectPx,
      atlasImg: HTMLImageElement,
      mouthIndex: number,
      alpha: number,
    ) => {
      if (!atlasImg.complete || !atlasImg.naturalWidth || !atlasImg.naturalHeight) return;

      const clampedIndex = Math.max(0, Math.min(mouthIndex, ovAtlas.frames.length - 1));
      const frame = ovAtlas.frames[clampedIndex];
      if (!frame) return;

      const sourceRect = getFrameRect(frame);
      const atlasW = atlasImg.naturalWidth;
      const atlasH = atlasImg.naturalHeight;

      const sx = sourceRect.x;
      const sy = sourceRect.y;
      const sxClamp = Math.max(0, Math.min(sx, atlasW - 1));
      const syClamp = Math.max(0, Math.min(sy, atlasH - 1));
      const x2 = Math.min(atlasW, sx + sourceRect.width);
      const y2 = Math.min(atlasH, sy + sourceRect.height);
      const swClamp = Math.max(0, x2 - sxClamp);
      const shClamp = Math.max(0, y2 - syClamp);
      if (swClamp < 1 || shClamp < 1) {
        if (clampedIndex === 0) {
          console.warn("TalkingHeadCanvas - Frame 0 source rect fully outside atlas; atlas size:", atlasW, "x", atlasH, "sourceRect:", sourceRect);
        }
        return;
      }

      const destRect = getDestRectForFrame(ovDest, clampedIndex);
      const scaleX = destRect.width / sourceRect.width;
      const scaleY = destRect.height / sourceRect.height;

      const scaledSourceAnchorOffsetX = frame.widthLeft * scaleX;
      const scaledSourceAnchorOffsetY = frame.heightAbove * scaleY;
      const destAnchorX = typeof ovDest.anchorX === "number" && !isNaN(ovDest.anchorX) ? ovDest.anchorX : DEFAULT_MOUTH_DEST_RECT_PX.anchorX;
      const destAnchorY = typeof ovDest.anchorY === "number" && !isNaN(ovDest.anchorY) ? ovDest.anchorY : DEFAULT_MOUTH_DEST_RECT_PX.anchorY;
      const dxFull = destAnchorX - scaledSourceAnchorOffsetX;
      const dyFull = destAnchorY - scaledSourceAnchorOffsetY;
      const dx = dxFull + (sxClamp - sx) * scaleX;
      const dy = dyFull + (syClamp - sy) * scaleY;
      const dw = swClamp * scaleX;
      const dh = shClamp * scaleY;

      if (isNaN(dx) || isNaN(dy) || dx < -10000 || dy < -10000) {
        console.error("TalkingHeadCanvas - Invalid destination position:", { dx, dy, dw, dh, destAnchorX, destAnchorY, ovDest, sourceRect, destRect });
      }

      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.imageSmoothingEnabled = !disableBlendingRef.current;
      ctx.imageSmoothingQuality = "low";
      if (!disableBlendingRef.current) {
        ctx.filter = "brightness(0.98) contrast(1.02) saturate(0.97)";
      }
      try {
        ctx.drawImage(atlasImg, sxClamp, syClamp, swClamp, shClamp, dx, dy, dw, dh);
      } finally {
        ctx.filter = "none";
        ctx.restore();
      }
    },
    [] // stable – all data passed as arguments
  );

  /** Draw all effective overlays at the given frame index and alpha (crossfade support). */
  const drawAllOverlays = useCallback(
    (ctx: CanvasRenderingContext2D, _w: number, _h: number, mouthIndex: number, alpha: number) => {
      const overlays = effectiveOverlaysRef.current;
      const images = overlayImagesRef.current;
      overlays.forEach((ov, i) => {
        const img = images[i];
        if (!img) return;
        drawOneOverlay(ctx, ov.atlas, ov.dest, img, mouthIndex, alpha);
      });
    },
    [drawOneOverlay]
  );

  /** Draw debug overlay (mouth + eye dest rects, state labels). */
  const drawDebugOverlay = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number, mouthIndex: number, eyeIndex: number) => {
      if (!debug) return;

      // Eye dest rect (blue) and state
      const eyeFrame = eyeAtlas.frames[Math.max(0, Math.min(eyeIndex, eyeAtlas.frames.length - 1))];
      ctx.strokeStyle = "#0066ff";
      ctx.lineWidth = 2;
      ctx.strokeRect(eyeDest.x, eyeDest.y, eyeDest.width, eyeDest.height);
      ctx.fillStyle = "rgba(0,0,0,0.85)";
      ctx.font = "bold 13px monospace";
      ctx.fillText(`Eye: ${eyeFrame?.state ?? "?"} (${eyeIndex})`, 8, 18);

      const clampedIndex = Math.max(0, Math.min(mouthIndex, primaryAtlas.frames.length - 1));
      const frame = primaryAtlas.frames[clampedIndex];
      if (!frame) return;

      const sourceRect = getFrameRect(frame);
      const destRect = getDestRectForFrame(primaryDest, clampedIndex);
      const scaleX = destRect.width / sourceRect.width;
      const scaleY = destRect.height / sourceRect.height;
      const scaledSourceAnchorOffsetX = frame.widthLeft * scaleX;
      const scaledSourceAnchorOffsetY = frame.heightAbove * scaleY;
      const destAnchorX = typeof primaryDest.anchorX === "number" && !isNaN(primaryDest.anchorX) ? primaryDest.anchorX : DEFAULT_MOUTH_DEST_RECT_PX.anchorX;
      const destAnchorY = typeof primaryDest.anchorY === "number" && !isNaN(primaryDest.anchorY) ? primaryDest.anchorY : DEFAULT_MOUTH_DEST_RECT_PX.anchorY;
      const dx = destAnchorX - scaledSourceAnchorOffsetX;
      const dy = destAnchorY - scaledSourceAnchorOffsetY;
      const dw = sourceRect.width * scaleX;
      const dh = sourceRect.height * scaleY;

      ctx.fillStyle = "#ff0000";
      ctx.beginPath();
      ctx.arc(destAnchorX, destAnchorY, 5, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "#00ff00";
      ctx.beginPath();
      ctx.arc(destAnchorX, destAnchorY, 5, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(0, 255, 0, 0.1)";
      ctx.fillRect(dx, dy, dw, dh);
      ctx.strokeStyle = "#00ff00";
      ctx.lineWidth = 3;
      ctx.strokeRect(dx, dy, dw, dh);

      const lines = [
        `Mouth frame ${clampedIndex}: ${frame.viseme} (${frame.phonemes})`,
        `Source: x=${sourceRect.x} y=${sourceRect.y} w=${sourceRect.width} h=${sourceRect.height}`,
        `Dest: x=${dx.toFixed(0)} y=${dy.toFixed(0)} w=${dw.toFixed(0)} h=${dh.toFixed(0)}`,
      ];
      lines.forEach((line, i) => {
        ctx.fillText(line, 8, 36 + i * 18);
      });
    },
    [debug, primaryAtlas, primaryDest, eyeAtlas, eyeDest]
  );

  /**
   * Build a feathered (box-blur) alpha mask that is 1.0 inside the diff bbox of
   * two overlay frames and 0.0 outside, with a smooth transition at the boundary.
   * Matches the approach used in the reference Python/TS crossfade scripts.
   */
  const computeFeatheredMask = useCallback(
    (dataA: Uint8ClampedArray, dataB: Uint8ClampedArray, w: number, h: number): Float32Array => {
      const LUMA_THR = 10;      // pixel difference threshold
      const PAD = Math.round(Math.min(w, h) * 0.12); // ~12% padding around diff
      const FEATHER = Math.round(Math.min(w, h) * 0.08); // ~8% blur radius
      const PASSES = 3;        // box-blur passes (approximates Gaussian)

      // 1. Find diff bounding box
      let x0 = w, y0 = h, x1 = -1, y1 = -1;
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const i = (y * w + x) * 4;
          const dr = dataA[i] - dataB[i];
          const dg = dataA[i + 1] - dataB[i + 1];
          const db = dataA[i + 2] - dataB[i + 2];
          const luma = Math.abs(0.2126 * dr + 0.7152 * dg + 0.0722 * db);
          if (luma > LUMA_THR) {
            if (x < x0) x0 = x; if (x > x1) x1 = x;
            if (y < y0) y0 = y; if (y > y1) y1 = y;
          }
        }
      }
      // No diff found → full mask
      if (x1 < 0) return new Float32Array(w * h).fill(1);

      x0 = Math.max(0, x0 - PAD); y0 = Math.max(0, y0 - PAD);
      x1 = Math.min(w, x1 + PAD); y1 = Math.min(h, y1 + PAD);

      // 2. Build hard rect mask
      let src = new Float32Array(w * h);
      for (let y = y0; y < y1; y++)
        for (let x = x0; x < x1; x++)
          src[y * w + x] = 1.0;

      if (FEATHER <= 0) return src;

      // 3. Three-pass box blur (fast feather approximation)
      const radius = Math.max(1, FEATHER);
      for (let p = 0; p < PASSES; p++) {
        const tmp = new Float32Array(w * h);
        // horizontal pass
        for (let y = 0; y < h; y++) {
          const row = y * w;
          const win = radius * 2 + 1;
          let sum = 0;
          for (let x = -radius; x <= radius; x++) sum += src[row + Math.max(0, x)];
          for (let x = 0; x < w; x++) {
            tmp[row + x] = sum / win;
            sum -= src[row + Math.max(0, x - radius)];
            sum += src[row + Math.min(w - 1, x + radius + 1)];
          }
        }
        // vertical pass
        const dst = new Float32Array(w * h);
        for (let x = 0; x < w; x++) {
          const win = radius * 2 + 1;
          let sum = 0;
          for (let y = -radius; y <= radius; y++) sum += tmp[Math.max(0, y) * w + x];
          for (let y = 0; y < h; y++) {
            dst[y * w + x] = sum / win;
            sum -= tmp[Math.max(0, y - radius) * w + x];
            sum += tmp[Math.min(h - 1, y + radius + 1) * w + x];
          }
        }
        src = dst;
      }
      // clamp to [0,1]
      for (let i = 0; i < src.length; i++) src[i] = Math.min(1, Math.max(0, src[i]));
      return src;
    },
    []
  );

  /**
   * ROI crossfade: render two overlay frames to OffscreenCanvases, detect the
   * changing pixels (mouth region), build a feathered mask, then pixel-blend
   * only within that region at the given eased progress. The result is
   * composited onto the main canvas via drawImage (alpha-aware).
   *
   * This prevents the "double mouth" ghost that standard whole-frame alpha
   * blending produces when sprite anchor positions differ between frames.
   */
  const drawROICrossfade = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number, fromIndex: number, toIndex: number, easedProgress: number) => {
      if (!("OffscreenCanvas" in globalThis)) {
        // Fallback: standard alpha blend
        drawAllOverlays(ctx, w, h, fromIndex, 1);
        drawAllOverlays(ctx, w, h, toIndex, easedProgress);
        return;
      }

      // Allocate or resize persistent OffscreenCanvases
      for (const ref of [offscreenARef, offscreenBRef, offscreenBlendRef] as typeof offscreenARef[]) {
        if (!ref.current || ref.current.width !== w || ref.current.height !== h) {
          ref.current = new OffscreenCanvas(w, h);
        }
      }
      const offA = offscreenARef.current!;
      const offB = offscreenBRef.current!;
      const offBlend = offscreenBlendRef.current!;

      const ctxA = offA.getContext("2d", { willReadFrequently: true }) as OffscreenCanvasRenderingContext2D | null;
      const ctxB = offB.getContext("2d", { willReadFrequently: true }) as OffscreenCanvasRenderingContext2D | null;
      if (!ctxA || !ctxB) {
        drawAllOverlays(ctx, w, h, fromIndex, 1);
        drawAllOverlays(ctx, w, h, toIndex, easedProgress);
        return;
      }

      // Render each frame to its offscreen canvas (clear first)
      ctxA.clearRect(0, 0, w, h);
      ctxB.clearRect(0, 0, w, h);
      const overlays = effectiveOverlaysRef.current;
      const images = overlayImagesRef.current;
      overlays.forEach((ov, i) => {
        const img = images[i];
        if (!img) return;
        drawOneOverlay(ctxA as unknown as CanvasRenderingContext2D, ov.atlas, ov.dest, img, fromIndex, 1);
        drawOneOverlay(ctxB as unknown as CanvasRenderingContext2D, ov.atlas, ov.dest, img, toIndex, 1);
      });

      const dataA = ctxA.getImageData(0, 0, w, h);
      const dataB = ctxB.getImageData(0, 0, w, h);

      // Get or compute the feathered diff mask for this frame pair
      const cacheKey = `${fromIndex}→${toIndex}`;
      let mask = roiMaskCacheRef.current.get(cacheKey);
      if (!mask) {
        mask = computeFeatheredMask(dataA.data, dataB.data, w, h);
        roiMaskCacheRef.current.set(cacheKey, mask);
        // Evict oldest entries beyond 200
        if (roiMaskCacheRef.current.size > 200) {
          roiMaskCacheRef.current.delete(roiMaskCacheRef.current.keys().next().value!);
        }
      }

      // Pixel-blend using mask × easedProgress as the per-pixel alpha
      const result = ctxA.createImageData(w, h);
      const dA = dataA.data, dB = dataB.data, dR = result.data;
      for (let i = 0; i < w * h; i++) {
        const alpha = mask[i] * easedProgress;
        const inv = 1 - alpha;
        const p = i * 4;
        dR[p] = dA[p] * inv + dB[p] * alpha;
        dR[p + 1] = dA[p + 1] * inv + dB[p + 1] * alpha;
        dR[p + 2] = dA[p + 2] * inv + dB[p + 2] * alpha;
        dR[p + 3] = dA[p + 3] * inv + dB[p + 3] * alpha;
      }

      // Composite blended overlay onto main canvas via drawImage (alpha-aware)
      const blendCtx = offBlend.getContext("2d") as OffscreenCanvasRenderingContext2D | null;
      if (blendCtx) {
        blendCtx.clearRect(0, 0, w, h);
        blendCtx.putImageData(result, 0, 0);
        ctx.drawImage(offBlend, 0, 0);
      }
    },
    [computeFeatheredMask, drawAllOverlays, drawOneOverlay]
  );

  /**
   * Draw rest.webp and, when a character eye atlas is loaded, overlay the eye sprite on top.
   * Use this everywhere rest.webp is shown so blinking works at idle too.
   */
  const drawRestAndEyes = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number, eyeIndex: number) => {
      drawRest(ctx, w, h);
      if (eyeAtlasRef.current?.complete && eyeAtlasRef.current.naturalWidth) {
        drawEyesOnly(ctx, eyeIndex);
      }
    },
    [drawRest, drawEyesOnly]
  );

  const drawFrame = useCallback(
    (ctx: CanvasRenderingContext2D, w: number, h: number, mouthIndex: number, eyeIndex: number) => {
      const rest = restImageRef.current;
      if ((!isSpeakingRef.current || mouthIndex === restFrameIndex) && rest?.complete && rest.naturalWidth) {
        drawRestAndEyes(ctx, w, h, eyeIndex);
      } else {
        drawBase(ctx, w, h);
        drawAllOverlays(ctx, w, h, mouthIndex, 1);
        // Eyes drawn after mouth overlays so they are never overwritten by a
        // full-face overlay (e.g. characters whose single part covers the whole face).
        drawEyesOnly(ctx, eyeIndex);
      }
      drawDebugOverlay(ctx, w, h, mouthIndex, eyeIndex);
    },
    [drawBase, drawEyesOnly, drawAllOverlays, drawDebugOverlay, drawRestAndEyes, restFrameIndex]
  );

  const tick = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas || !loaded) return;

    const atlasFrameCount = primaryAtlas.frames.length;
    const inPreviewMode = typeof previewMouthIndex === "number";
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;
    const t = getCurrentTime();
    const audioTimeSec = audioEl && !isNaN(audioEl.currentTime) ? audioEl.currentTime : 0;

    const eyeIndex = resolvedEyeFrameIndex;

    if (audioEl && (audioEl.paused || audioEl.ended) && visemeEvents.length > 0) {
      // Audio finished: show rest.webp directly, bypassing isSpeakingRef which may lag
      const rest = restImageRef.current;
      if (rest?.complete && rest.naturalWidth) {
        drawRestAndEyes(ctx, w, h, eyeIndex);
      } else {
        drawFrame(ctx, w, h, restFrameIndex, eyeIndex);
      }
      onTickRef.current?.({ audioTimeSec, syncOffsetSec, visemeIndex: restFrameIndex });
      return;
    }

    // Audio fully ended and viseme events already cleared but external speaking prop may still
    // be true (app-level state hasn't caught up yet) — show rest.webp immediately.
    if (!inPreviewMode && audioEl && audioEl.ended && visemeEvents.length === 0) {
      const rest = restImageRef.current;
      if (rest?.complete && rest.naturalWidth) {
        drawRestAndEyes(ctx, w, h, eyeIndex);
        drawDebugOverlay(ctx, w, h, restFrameIndex, eyeIndex);
      } else {
        drawBase(ctx, w, h);
        drawAllOverlays(ctx, w, h, restFrameIndex, 1);
        drawEyesOnly(ctx, eyeIndex);
        drawDebugOverlay(ctx, w, h, restFrameIndex, eyeIndex);
      }
      onTickRef.current?.({ audioTimeSec, syncOffsetSec, visemeIndex: restFrameIndex });
      rafRef.current = requestAnimationFrame(tick);
      return;
    }

    if (onTickRef.current && performance.now() - lastOnTickTimeRef.current >= 100) {
      lastOnTickTimeRef.current = performance.now();
      const vi = getCurrentVisemeIndex();
      onTickRef.current({ audioTimeSec, syncOffsetSec, visemeIndex: vi });
    }

    // Preview mode: single frame
    if (inPreviewMode) {
      const targetIndex = Math.max(0, Math.min(previewMouthIndex!, atlasFrameCount - 1));
      drawFrame(ctx, w, h, targetIndex, eyeIndex);
      rafRef.current = requestAnimationFrame(tick);
      return;
    }

    // Timeline mode (viseme events + speaking): interpolated blend at 60fps
    const useInterpolated = visemeEvents.length > 0 && speaking;
    if (useInterpolated) {
      const interp = getInterpolatedViseme();
      const primary = Math.max(0, Math.min(interp.primaryIndex, atlasFrameCount - 1));
      const secondary = Math.max(0, Math.min(interp.secondaryIndex, atlasFrameCount - 1));
      const primaryWeight = Math.max(0, Math.min(1, interp.primaryWeight));

      // Track primary changes and start arrival crossfade on each new frame
      if (primary !== arrivalPrevPrimaryRef.current) {
        arrivalFromRef.current = arrivalPrevPrimaryRef.current >= 0
          ? arrivalPrevPrimaryRef.current
          : primary;
        arrivalStartRef.current = t;
        arrivalPrevPrimaryRef.current = primary;
      }

      if (primary !== lastMouthIndexRef.current) {
        lastMouthIndexRef.current = primary;
        onMouthIndexChange?.(primary);
        setCurrentMouthIndex(primary);
      }

      // Arrival blend: smoothly fade from the previous frame to the current one
      const arrivalElapsed = t - arrivalStartRef.current;
      const arrivalLinear = Math.min(1, arrivalElapsed / ARRIVAL_DURATION_S);
      const arrivalProgress = smoothstep(arrivalLinear);
      const inArrival = !disableBlendingRef.current &&
        arrivalProgress < 1 &&
        arrivalFromRef.current >= 0 &&
        arrivalFromRef.current !== primary;

      // At a full rest pause (REST frame, arrival done), use rest.webp.
      const atRestPause = primary === restFrameIndex && primaryWeight >= 0.9999 && !inArrival;
      const restImg = restImageRef.current;
      if (atRestPause && restImg?.complete && restImg.naturalWidth) {
        drawRestAndEyes(ctx, w, h, eyeIndex);
        drawDebugOverlay(ctx, w, h, 0, eyeIndex);
      } else {
        drawBase(ctx, w, h);
        if (inArrival) {
          // Arrival crossfade: fade from previous frame into the newly arrived frame
          drawROICrossfade(ctx, w, h, arrivalFromRef.current, primary, arrivalProgress);
        } else if (primaryWeight >= 0.9999 || disableBlendingRef.current) {
          drawAllOverlays(ctx, w, h, primary, 1);
        } else {
          // Coarticulation: blend current frame toward next in last segment of each phoneme
          drawROICrossfade(ctx, w, h, secondary, primary, primaryWeight);
        }
        // Eyes drawn after mouth overlays so they sit on top, even when the
        // mouth part covers the entire face (e.g. single full-face overlay).
        drawEyesOnly(ctx, eyeIndex);
        drawDebugOverlay(ctx, w, h, primary, eyeIndex);
      }
      rafRef.current = requestAnimationFrame(tick);
      return;
    }

    // Demo mode (no timeline, speaking): discrete index + eased crossfade over 2–3 frames
    const targetIndex = getCurrentVisemeIndex();
    if (targetIndex !== currentVisemeRef.current) {
      previousVisemeRef.current = currentVisemeRef.current >= 0 ? currentVisemeRef.current : targetIndex;
      currentVisemeRef.current = targetIndex;
      transitionStartTimeRef.current = t;
    }

    const elapsed = t - transitionStartTimeRef.current;
    const linearProgress = Math.min(1, elapsed / CROSSFADE_DURATION_S);
    const blendProgress = smoothstep(linearProgress);
    const crossfade =
      blendProgress < 1 &&
      previousVisemeRef.current >= 0 &&
      previousVisemeRef.current !== currentVisemeRef.current;

    const mouthDestKey = `${primaryDest.anchorX},${primaryDest.anchorY},${primaryDest.widthLeft},${primaryDest.widthRight},${primaryDest.heightAbove},${primaryDest.heightBelow},${primaryDest.heightAboveRow2 ?? ""},${primaryDest.heightBelowRow2 ?? ""}`;
    const mouthDestChanged = mouthDestKey !== lastMouthDestRef.current;
    const currentFrame = primaryAtlas.frames[targetIndex];
    const atlasFrameKey = currentFrame
      ? `${targetIndex}:${currentFrame.anchorX},${currentFrame.anchorY},${currentFrame.widthLeft},${currentFrame.widthRight},${currentFrame.heightAbove},${currentFrame.heightBelow}`
      : "";
    const atlasFrameChanged = atlasFrameKey !== lastAtlasFrameKeyRef.current;

    const eyeCalibrationKey = `${eyeDest.x},${eyeDest.y},${eyeDest.width},${eyeDest.height}|${eyeAtlas.frames.map((f) => `${f.x},${f.y},${f.width},${f.height}`).join(";")}`;
    const eyeCalibrationChanged = eyeCalibrationKey !== lastEyeCalibrationKeyRef.current;

    const eyeFrameIndexChanged = eyeIndex !== lastResolvedEyeFrameIndexRef.current;

    const needsRedraw =
      targetIndex !== lastMouthIndexRef.current ||
      crossfade ||
      debug ||
      mouthDestChanged ||
      atlasFrameChanged ||
      eyeCalibrationChanged ||
      eyeFrameIndexChanged;

    if (targetIndex !== lastMouthIndexRef.current) {
      onMouthIndexChange?.(targetIndex);
      setCurrentMouthIndex(targetIndex);
    }
    if (mouthDestChanged) {
      lastMouthDestRef.current = mouthDestKey;
      lastMouthIndexRef.current = -1;
    }
    if (atlasFrameChanged) {
      lastAtlasFrameKeyRef.current = atlasFrameKey;
    }
    if (eyeCalibrationChanged) {
      lastEyeCalibrationKeyRef.current = eyeCalibrationKey;
    }
    if (eyeFrameIndexChanged) {
      lastResolvedEyeFrameIndexRef.current = eyeIndex;
    }
    lastMouthIndexRef.current = targetIndex;

    if (needsRedraw) {
      if (crossfade && !disableBlendingRef.current) {
        drawBase(ctx, w, h);
        drawROICrossfade(ctx, w, h, previousVisemeRef.current, currentVisemeRef.current, blendProgress);
        drawEyesOnly(ctx, eyeIndex);
        drawDebugOverlay(ctx, w, h, targetIndex, eyeIndex);
      } else {
        drawFrame(ctx, w, h, targetIndex, eyeIndex);
      }
    }

    rafRef.current = requestAnimationFrame(tick);
  }, [
    loaded,
    getCurrentVisemeIndex,
    getInterpolatedViseme,
    getCurrentTime,
    drawFrame,
    drawBase,
    drawEyesOnly,
    drawRestAndEyes,
    drawAllOverlays,
    drawDebugOverlay,
    drawRest,
    debug,
    onMouthIndexChange,
    primaryDest,
    eyeDest,
    eyeAtlas,
    previewMouthIndex,
    primaryAtlas,
    visemeEvents.length,
    speaking,
    resolvedEyeFrameIndex,
    syncOffsetSec,
    restFrameIndex,
    drawROICrossfade,
  ]);

  // Load rest image independently; silently skip if URL absent or fetch fails.
  useEffect(() => {
    if (!restImageUrlProp) {
      restImageRef.current = null;
      return;
    }
    const img = new Image();
    img.crossOrigin = "";
    const url = restImageUrlProp.startsWith("/") ? `${BASE}${restImageUrlProp}` : restImageUrlProp;
    img.onload = () => {
      restImageRef.current = img;
      // Invalidate the "last drawn" sentinel so the next tick forces a redraw
      // with rest.webp (the image may have arrived after the first frame was painted).
      lastMouthIndexRef.current = -1;
    };
    img.onerror = () => { restImageRef.current = null; };
    img.src = url;
    return () => { restImageRef.current = null; };
  }, [restImageUrlProp]);

  // Stable key for the loading effect: changes whenever any overlay URL or base URL changes.
  const overlayUrlsKey = effectiveOverlays.map((o) => o.atlas.imageUrl).join("|");

  // Load images (parent, all overlay atlases, eyes)
  useEffect(() => {
    setLoaded(false);
    let cancelled = false;
    const parentImg = new Image();
    const eyeImg = new Image();
    parentImg.crossOrigin = "";
    eyeImg.crossOrigin = "";

    const resolvedBaseUrl = baseImageUrlProp ?? DEFAULT_PARENT_IMAGE_URL;

    const parentLoaded = new Promise<void>((resolve, reject) => {
      parentImg.onload = () => {
        if (cancelled) return;
        setParentNaturalSize({ width: parentImg.naturalWidth, height: parentImg.naturalHeight });
        resolve();
      };
      parentImg.onerror = () => {
        if (cancelled) return;
        reject(new Error(`Failed to load ${resolvedBaseUrl}`));
      };
      parentImg.src = resolvedBaseUrl;
    });

    // Load all overlay atlas images in parallel.
    // For the legacy single-atlas case (no overlaysProp) we keep the fallback URL behaviour.
    const overlaysSnapshot = effectiveOverlaysRef.current;
    const overlayImgs = overlaysSnapshot.map(() => {
      const img = new Image();
      img.crossOrigin = "";
      return img;
    });
    const overlayPromises = overlaysSnapshot.map((ov, i) => {
      const img = overlayImgs[i];
      const primaryUrl = ov.atlas.imageUrl.startsWith("/") ? `${BASE}${ov.atlas.imageUrl}` : ov.atlas.imageUrl;
      return new Promise<void>((resolve, reject) => {
        const tryUrl = (url: string, isFallback: boolean) => {
          img.onload = () => resolve();
          img.onerror = () => {
            if (cancelled) return;
            // Only use fallback for the legacy default atlas (single overlay, default URL)
            if (!isFallback && !overlaysProp && i === 0 && primaryUrl !== MOUTH_ATLAS_FALLBACK_URL) {
              img.src = MOUTH_ATLAS_FALLBACK_URL;
              tryUrl(MOUTH_ATLAS_FALLBACK_URL, true);
            } else {
              reject(new Error(`Failed to load ${ov.atlas.imageUrl}`));
            }
          };
          img.src = url;
        };
        tryUrl(primaryUrl, false);
      });
    });

    const eyeUrl = eyeAtlas.imageUrl.startsWith("/") ? `${BASE}${eyeAtlas.imageUrl}` : eyeAtlas.imageUrl;
    const eyeLoaded = new Promise<void>((resolve, reject) => {
      eyeImg.onload = () => { resolve(); };
      eyeImg.onerror = () => {
        if (cancelled) return;
        reject(new Error(`Failed to load ${eyeAtlas.imageUrl}`));
      };
      eyeImg.src = eyeUrl;
    });

    parentLoaded
      .then(() => {
        if (cancelled) return;
        parentImageRef.current = parentImg;
        setLoadError(null);
        return Promise.all(overlayPromises);
      })
      .then(() => {
        if (cancelled) return;
        overlayImagesRef.current = overlayImgs;
        setMouthLoadError(null);
        // Eye atlas is optional — if it fails, log a warning but don't block or show error UI.
        return eyeLoaded
          .then(() => {
            if (cancelled) return;
            eyeAtlasRef.current = eyeImg;
            // Force the next animation tick to redraw so the eye overlay is
            // painted immediately, even if needsRedraw was already false when
            // the image finished loading asynchronously.
            lastResolvedEyeFrameIndexRef.current = -1;
            setEyeLoadError(null);
          })
          .catch((e) => {
            console.debug("[TalkyHeads] Eye spritesheet not found (optional):", e?.message ?? e);
            eyeAtlasRef.current = null;
          });
      })
      .then(() => {
        if (cancelled) return;
        setLoaded(true);
      })
      .catch((e) => {
        if (cancelled) return;
        if (!parentImageRef.current) {
          setLoadError(e instanceof Error ? e.message : String(e));
        } else {
          setMouthLoadError(e instanceof Error ? e.message : String(e));
          setLoaded(true);
        }
      });
    return () => {
      cancelled = true;
      parentImageRef.current = null;
      overlayImagesRef.current = [];
      eyeAtlasRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [overlayUrlsKey, eyeAtlas.imageUrl, baseImageUrlProp]);

  useEffect(() => {
    onAssetsReady?.(loaded);
  }, [loaded, onAssetsReady]);

  // Setup canvas size and animation loop
  useEffect(() => {
    if (!loaded || !parentNaturalSize) return;
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Use the natural image dimensions (or explicit prop overrides) for the
    // canvas backing store. Do NOT set canvas.style.width/height to fixed px —
    // the container + CSS rules (width:100%, height:100%, object-fit) handle
    // responsive layout. Setting explicit pixel sizes would fight the CSS
    // !important overrides used for circle/square shape modes.
    const w = widthProp ?? parentNaturalSize.width;
    const h = heightProp ?? parentNaturalSize.height;
    if (canvas.width !== w || canvas.height !== h) {
      canvas.width = w;
      canvas.height = h;
      lastMouthIndexRef.current = -1;
    }
    // For non-circle shapes: set the container's aspect-ratio so the card
    // grows to portrait height and the canvas fills it without squishing.
    // For circle: the outer card is already 1:1 square; setting a portrait
    // aspect-ratio here would turn border-radius:50% into an ellipse.
    if (containerRef.current) {
      containerRef.current.style.aspectRatio = shape !== "circle" ? `${w} / ${h}` : "";
    }

    demoStartTimeRef.current = performance.now();
    // Force eye overlay to redraw on the very first tick of any new loop,
    // so open eyes always paint after a blink cycle or atlas change.
    lastResolvedEyeFrameIndexRef.current = -1;
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [loaded, parentNaturalSize, widthProp, heightProp, shape, tick]);

  useEffect(() => {
    if (debug) {
      demoStartTimeRef.current = performance.now();
      lastMouthIndexRef.current = -1;
    }
  }, [debug]);

  if (loadError) {
    return (
      <div className={`flex items-center justify-center bg-gray-200 text-red-600 text-sm p-4 ${className}`}>
        {loadError}
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className={`relative w-full min-h-[80px] rounded-lg overflow-hidden ${className}`}
      style={{
        position: "relative",
        width: "100%",
        minHeight: "80px",
        overflow: "hidden",
        backgroundColor: "transparent",
        ...(shape === "circle" ? { borderRadius: "50%" } : {}),
      }}
    >
      <canvas
        ref={canvasRef}
        className="absolute inset-0 w-full h-full block"
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          display: "block",
          objectFit: "contain",
          objectPosition: "center top",
          backgroundColor: "#ffffff",
          zIndex: 2,
        }}
        aria-label="Talking head avatar"
      />
      {fallbackImageUrl && (
        <div
          className="absolute inset-0 pointer-events-none select-none"
          aria-hidden="true"
          style={{
            position: "absolute",
            inset: 0,
            zIndex: 1,
            opacity: loaded ? 0 : 1,
            transition: "opacity 200ms ease",
            pointerEvents: "none",
          }}
        >
          <img
            src={fallbackImageUrl}
            alt=""
            draggable={false}
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
              objectPosition: "center top",
              userSelect: "none",
              pointerEvents: "none",
            }}
          />
        </div>
      )}
      {debug && (
        <div
          className="absolute top-1 left-1 bg-black/70 text-green-400 text-xs font-mono px-2 py-1 rounded"
          style={{ position: "absolute", top: 4, left: 4, zIndex: 10, fontSize: 11, fontFamily: "monospace", background: "rgba(0,0,0,0.7)", color: "#4ade80", padding: "2px 6px", borderRadius: 4 }}
        >
          mouth: {currentMouthIndex} | eye: {eyeAtlas.frames[resolvedEyeFrameIndex]?.state ?? "?"} ({resolvedEyeFrameIndex})
        </div>
      )}
      {mouthLoadError && (
        <div
          className="absolute bottom-1 left-1 right-1 bg-amber-800/90 text-amber-100 text-xs px-2 py-1 rounded text-center"
          style={{ position: "absolute", bottom: 4, left: 4, right: 4, zIndex: 10, fontSize: 11, background: "rgba(120,53,15,0.9)", color: "#fef3c7", padding: "4px 8px", borderRadius: 4, textAlign: "center" }}
        >
          Mouth image failed: check <code style={{ background: "rgba(69,26,3,0.5)", padding: "0 2px" }}>{primaryAtlas.imageUrl}</code> in public/
        </div>
      )}
      {eyeLoadError && (
        <div
          className="absolute bottom-8 left-1 right-1 bg-blue-900/90 text-blue-100 text-xs px-2 py-1 rounded text-center"
          style={{ position: "absolute", bottom: 36, left: 4, right: 4, zIndex: 10, fontSize: 11, background: "rgba(30,58,138,0.9)", color: "#dbeafe", padding: "4px 8px", borderRadius: 4, textAlign: "center" }}
        >
          Eyes image failed: check <code style={{ background: "rgba(23,37,84,0.5)", padding: "0 2px" }}>{eyeAtlas.imageUrl}</code> in public/
        </div>
      )}
    </div>
  );
}
