import { useCallback, useRef, useState } from "react";
import type { TTSConfig, TTSResult } from "./types";
import { elevenLabsSynthesize } from "./providers/elevenlabs";
import { googleTTSSynthesize } from "./providers/google";
import { proxySynthesize } from "./providers/proxy";

export type UseTTSState = {
  loading: boolean;
  error: string | null;
};

export type UseTTSReturn = UseTTSState & {
  /** Synthesize text and return audio blob + optional alignment. */
  synthesize(text: string): Promise<TTSResult>;
  /** Cancel any in-progress synthesis request. */
  cancel(): void;
};

/**
 * React hook for TTS synthesis.
 * Returns { synthesize, cancel, loading, error }.
 *
 * Usage:
 *   const { synthesize, loading, error } = useTTS(config);
 *   const { audioBlob, alignment } = await synthesize("Hello world");
 *   headRef.current.speak("Hello world", audioBlob, alignment);
 */
export function useTTS(config: TTSConfig): UseTTSReturn {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const cancel = useCallback(() => {
    abortRef.current?.abort();
    abortRef.current = null;
    setLoading(false);
  }, []);

  const synthesize = useCallback(
    async (text: string): Promise<TTSResult> => {
      cancel();
      const ac = new AbortController();
      abortRef.current = ac;
      setLoading(true);
      setError(null);

      try {
        let result: TTSResult;

        if (config.mode === "proxy") {
          result = await proxySynthesize(
            text,
            config.proxyUrl,
            config.provider ?? "elevenlabs",
            config.voice,
            "mp3",
            config.speed,
            config.apiKey,
            ac.signal
          );
        } else if (config.provider === "elevenlabs") {
          result = await elevenLabsSynthesize(
            text,
            config.apiKey,
            config.voice ?? "",
            "mp3",
            config.speed ?? 1.0,
            ac.signal
          );
        } else {
          result = await googleTTSSynthesize(
            text,
            config.apiKey,
            config.voice,
            config.language,
            "mp3",
            ac.signal
          );
        }

        setLoading(false);
        return result;
      } catch (e) {
        if ((e as Error).name === "AbortError") {
          setLoading(false);
          throw e;
        }
        const msg = e instanceof Error ? e.message : String(e);
        setError(msg);
        setLoading(false);
        throw e;
      }
    },
    [config, cancel]
  );

  return { synthesize, cancel, loading, error };
}
