import type { TTSFormat, TTSProvider, TTSResult } from "../types";

type TimestampResponse = {
  audio_base64: string;
  alignment: {
    characters: string[];
    character_start_times_seconds: number[];
    character_end_times_seconds: number[];
  } | null;
};

/**
 * Call a developer-supplied backend proxy.
 *
 * Expected backend endpoints (match the trainer/ project shape):
 *
 *   POST {proxyUrl}/tts
 *     body:     { text, provider, voice?, format?, speed? }
 *     response: audio bytes (Content-Type: audio/mpeg or audio/wav)
 *
 *   POST {proxyUrl}/tts-with-timestamps    ← ElevenLabs only
 *     body:     { text, voice?, format?, speed? }
 *     response: { audio_base64: string, alignment: {...} | null }
 *
 * When the backend returns HTTP 501 for tts-with-timestamps, falls back to plain /tts.
 */
export async function proxySynthesize(
  text: string,
  proxyUrl: string,
  provider: TTSProvider = "elevenlabs",
  voice?: string,
  format: TTSFormat = "mp3",
  speed?: number,
  apiKey?: string,
  signal?: AbortSignal
): Promise<TTSResult> {
  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (apiKey) headers["X-API-Key"] = apiKey;

  const base = proxyUrl.replace(/\/$/, "");

  // For ElevenLabs, try timestamps endpoint first (gives alignment for accurate lip-sync)
  if (provider === "elevenlabs") {
    try {
      const fetchStart = performance.now();
      const res = await fetch(`${base}/tts-with-timestamps`, {
        method: "POST",
        headers,
        body: JSON.stringify({ text, voice, format, speed }),
        signal,
      });
      const fetchEnd = performance.now();
      const cacheStatus = res.headers.get("X-Cache") ?? "UNKNOWN";

      if (res.ok) {
        const data = (await res.json()) as TimestampResponse;
        if (data.audio_base64) {
          const decodeStart = performance.now();
          const binary = atob(data.audio_base64);
          const bytes = new Uint8Array(binary.length);
          for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
          const decodeEnd = performance.now();

          const mimeType = format === "mp3" ? "audio/mpeg" : "audio/wav";
          const alignment = data.alignment ?? null;

          console.debug(
            `[TalkyHeads] proxy /tts-with-timestamps [${cacheStatus}]` +
            ` — fetch: ${(fetchEnd - fetchStart).toFixed(0)}ms` +
            ` | decode: ${(decodeEnd - decodeStart).toFixed(0)}ms` +
            ` | audio_b64_len: ${data.audio_base64.length}` +
            ` | align_chars: ${alignment?.characters?.length ?? "none"}`
          );

          if (alignment) {
            console.groupCollapsed(`[TalkyHeads] proxy alignment — "${text.slice(0, 60)}${text.length > 60 ? "…" : ""}"`);
            console.table(
              alignment.characters.map((ch, i) => ({
                char:    ch,
                start_s: alignment.character_start_times_seconds[i]?.toFixed(3),
                end_s:   alignment.character_end_times_seconds[i]?.toFixed(3),
              }))
            );
            console.groupEnd();
          } else {
            console.warn("[TalkyHeads] proxy /tts-with-timestamps returned no alignment — lip-sync will use text-based fallback.");
          }

          return {
            audioBlob: new Blob([bytes], { type: mimeType }),
            alignment,
          };
        }
      }
      // 501 = provider doesn't support timestamps; fall through to plain /tts
    } catch {
      // Network error on timestamps endpoint; fall through
    }
  }

  // Plain /tts fallback (all providers, or ElevenLabs timestamps unavailable)
  const res = await fetch(`${base}/tts`, {
    method: "POST",
    headers,
    body: JSON.stringify({ text, provider, voice, format, speed }),
    signal,
  });

  if (!res.ok) {
    const detail = await res.text().catch(() => res.statusText);
    throw new Error(`TTS proxy failed (${res.status}): ${detail}`);
  }

  const audioBlob = await res.blob();
  return { audioBlob, alignment: null };
}
